7. **Hardcoded port** — should read from `process.env.PORT` with a safe default.
8. **No graceful shutdown** — SIGTERM/SIGINT aren't handled, which matters for container deployments.
9. **Sensitive data in `/users`** — returning emails without auth; fine for a demo, but worth flagging.
10. **`console.log` instead of a structured logger** — hard to audit in production.

## Suggested rewrite

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// Body size limit (defense against memory-exhaustion)
app.use(express.json({ limit: '100kb' }));

// Basic rate limiting
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // TODO: add authentication/authorization before exposing PII
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error handler — never leak stack traces
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}

module.exports = app;
```

## Input validation pattern (for when routes take input)

When you add routes with params/body, validate before use:

```js
const { z } = require('zod');

const UserIdSchema = z.object({ id: z.coerce.number().int().positive() });

app.get('/users/:id', (req, res, next) => {
  const parsed = UserIdSchema.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... use parsed.data.id
});
